    setState(() {
      _isRealtimeConnected = transition.isRealtimeConnected;
      _realtimeDisconnectedAtUtc = transition.realtimeDisconnectedAtUtc;
      _lastReconnectAtUtc = transition.lastReconnectAtUtc;
      _lastReconnectLatency = transition.lastReconnectLatency;
    });
